export const createInvitation = <ThrowOnError extends boolean = false>(options: Options<CreateInvitationData, ThrowOnError>) => (options.client ?? client).post<CreateInvitationResponses, CreateInvitationErrors, ThrowOnError>({
    requestValidator: async (data) => await zCreateInvitationData.parseAsync(data),
    responseValidator: async (data) => await zCreateInvitationResponse.parseAsync(data),
    security: [{ scheme: 'bearer', type: 'http' }],
    url: '/households/{householdId}/invitations',
    ...options,
    headers: {
        'Content-Type': 'application/json',
        ...options.headers
    }
});

